// 5 dilim pizza yeyirik
for (let i = 1; i <= 5; i++) {
  console.log("Pizza dilimi " + i + " yendi!");
}
// nəticə:
// Pizza dilimi 1 yendi!
// Pizza dilimi 2 yendi!
// Pizza dilimi 3 yendi!
// Pizza dilimi 4 yendi!
// Pizza dilimi 5 yendi!

// 3 dəfə mesaj göstəririk
for (let i = 0; i < 3; i++) {
  console.log("Mesaj " + i);
}
// nəticə:
// Mesaj 0
// Mesaj 1
// Mesaj 2

// Geriyə sayma nümunəsi
for (let i = 5; i >= 1; i--) {
  console.log("Qalan dilim: " + i);
}
// nəticə:
// Qalan dilim: 5
// Qalan dilim: 4
// Qalan dilim: 3
// Qalan dilim: 2
// Qalan dilim: 1

// Müqayisə nümunəsi
// for ilə
for (let i = 0; i < 2; i++) {
  console.log("for: Mesaj " + i);
}
// nəticə: for: Mesaj 0, for: Mesaj 1

// for...of ilə
const array = ["alma", "banan"];
for (let item of array) {
  console.log("for...of: " + item);
}
// nəticə: for...of: alma, for...of: banan

