// Eat 5 slices of pizza
for (let i = 1; i <= 5; i++) {
  console.log("Pizza slice " + i + " eaten!");
}
// Output:
// Pizza slice 1 eaten!
// Pizza slice 2 eaten!
// Pizza slice 3 eaten!
// Pizza slice 4 eaten!
// Pizza slice 5 eaten!

// Show a message 3 times
for (let i = 0; i < 3; i++) {
  console.log("Message " + i);
}
// Output:
// Message 0
// Message 1
// Message 2

// Counting down example
for (let i = 5; i >= 1; i--) {
  console.log("Slices left: " + i);
}
// Output:
// Slices left: 5
// Slices left: 4
// Slices left: 3
// Slices left: 2
// Slices left: 1

// Comparison example
// With for
for (let i = 0; i < 2; i++) {
  console.log("for: Message " + i);
}
// Output: for: Message 0, for: Message 1

// With for...of
const array = ["apple", "banana"];
for (let item of array) {
  console.log("for...of: " + item);
}
// Output: for...of: apple, for...of: banana

