// Съедаем 5 кусков пиццы
for (let i = 1; i <= 5; i++) {
  console.log("Кусок пиццы " + i + " съеден!");
}
// Вывод:
// Кусок пиццы 1 съеден!
// Кусок пиццы 2 съеден!
// Кусок пиццы 3 съеден!
// Кусок пиццы 4 съеден!
// Кусок пиццы 5 съеден!

// Показываем сообщение 3 раза
for (let i = 0; i < 3; i++) {
  console.log("Сообщение " + i);
}
// Вывод:
// Сообщение 0
// Сообщение 1
// Сообщение 2

// Пример счёта в обратном порядке
for (let i = 5; i >= 1; i--) {
  console.log("Осталось кусков: " + i);
}
// Вывод:
// Осталось кусков: 5
// Осталось кусков: 4
// Осталось кусков: 3
// Осталось кусков: 2
// Осталось кусков: 1

// Пример сравнения
// С for
for (let i = 0; i < 2; i++) {
  console.log("for: Сообщение " + i);
}
// Вывод: for: Сообщение 0, for: Сообщение 1

// С for...of
const array = ["яблоко", "банан"];
for (let item of array) {
  console.log("for...of: " + item);
}
// Вывод: for...of: яблоко, for...of: банан

